const fs = require('fs');
const path = require('path');

const PROJECT = '/mnt/d/NAS-DATA/antenna-engine';
const PY = path.join(PROJECT, 'python/antenna_ml');
const CORE = path.join(PROJECT, 'src-tauri/src/core');

const readFile = (p) => {
  try { return fs.readFileSync(p, 'utf8'); } catch { return '# FILE NOT FOUND'; }
};

const context = {
  types_py: readFile(path.join(PY, 'types.py')),
  api_schema: readFile(path.join(PY, 'api_schema.py')),
  existing_fdtd: readFile(path.join(PY, 'fdtd/__init__.py')),
  geometry_rs: readFile(path.join(CORE, 'geometry.rs')),
  solver_rs: readFile(path.join(CORE, 'solver.rs')),
  bridge_rs: readFile(path.join(PROJECT, 'src-tauri/src/bridge.rs')),
  requirements: readFile(path.join(PROJECT, 'python/requirements.txt')),
};

// Ensure fdtd directory exists
const fdtdDir = path.join(PY, 'fdtd');
if (!fs.existsSync(fdtdDir)) fs.mkdirSync(fdtdDir, { recursive: true });

return [{ json: { context } }];

const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

const PROJECT = '/mnt/d/NAS-DATA/antenna-engine';
const CORE = path.join(PROJECT, 'src-tauri/src/core');

const agents = ['FDTD Core', 'FDTD Bridge'];
const fileRegex = /<file path="([^"]+)">\n?([\s\S]*?)<\/file>/g;
const results = {};
let filesWritten = 0;

for (const agentName of agents) {
  try {
    const output = $(agentName).item.json.output || '';
    let match;
    const regex = new RegExp(fileRegex.source, fileRegex.flags);
    while ((match = regex.exec(output)) !== null) {
      const fullPath = path.join(PROJECT, match[1]);
      const dir = path.dirname(fullPath);
      if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
      fs.writeFileSync(fullPath, match[2].trim());
      results[match[1]] = `WRITTEN (${match[2].length} chars)`;
      filesWritten++;
    }
  } catch (e) {
    results[agentName] = `ERROR: ${e.message}`;
  }
}

// Update mod.rs
const modPath = path.join(CORE, 'mod.rs');
let modContent = fs.readFileSync(modPath, 'utf8');
if (!modContent.includes('pub mod fdtd_bridge')) {
  modContent = modContent.replace('pub mod solver;', 'pub mod fdtd_bridge;\npub mod solver;');
  fs.writeFileSync(modPath, modContent);
}

// Cargo check
let cargoResult = '';
try {
  cargoResult = execSync('cd src-tauri && cargo check 2>&1', { cwd: PROJECT, timeout: 180000 }).toString();
  cargoResult = cargoResult.includes('error[') ? cargoResult : 'OK';
} catch (e) {
  cargoResult = e.stdout?.toString() || e.message;
}

// Python syntax check
let pythonResult = '';
try {
  pythonResult = execSync('python3 -m py_compile python/antenna_ml/fdtd/yee_grid.py && python3 -m py_compile python/antenna_ml/fdtd/pml.py && python3 -m py_compile python/antenna_ml/fdtd/sources.py && python3 -m py_compile python/antenna_ml/fdtd/runner.py && echo OK', { cwd: PROJECT, timeout: 30000 }).toString();
} catch (e) {
  pythonResult = e.stdout?.toString() || e.message;
}

return [{ json: { filesWritten, results, cargoResult, pythonResult } }];

