const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

const PROJECT = '/mnt/d/NAS-DATA/antenna-engine';
const prev = $('Write + Check').item.json;
const needsFix = prev.cargoResult !== 'OK' || !prev.pythonResult.includes('OK');
let fixResult = 'No fix needed';

if (needsFix) {
  const output = $('Self-Fix Agent').item.json.output || '';
  const fileRegex = /<file path="([^"]+)">\n?([\s\S]*?)<\/file>/g;
  let match;
  while ((match = fileRegex.exec(output)) !== null) {
    const fullPath = path.join(PROJECT, match[1]);
    const dir = path.dirname(fullPath);
    if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
    fs.writeFileSync(fullPath, match[2].trim());
  }
  fixResult = 'Fixes applied';
}

let gitResult = '';
try {
  execSync('git add -A', { cwd: PROJECT });
  execSync('git commit -m "feat(fdtd): add 3D FDTD solver with CPML\n\nYee grid implementation, convolutional PML,\nGaussian/sinusoidal/gap sources, NF2FF transform,\nRust bridge for Tauri integration."', { cwd: PROJECT });
  execSync('git push origin main', { cwd: PROJECT });
  gitResult = 'Committed and pushed';
} catch (e) {
  gitResult = 'Git: ' + e.message;
}

return [{ json: { ...prev, fixResult, gitResult, phase: 'fdtd-python', status: 'complete' } }];
